('old-data-berta2-all-20260501-01', '0a4ab9eb', '9360a373', 'l.calpetard@otisud.com', U&'"Tr\00E8s bel \00E9v\00E9nement, bonne communication et organisation. Pourriez vous envisager d''organiser l''\00E9v\00E9nement sur 2 jours?"', '2024-05-21 00:00:00', U&'\+01F642', U&'Trait\00E9e', 'true', 'true', 'Commentaires', U&'{"ID":"0a4ab9eb","User":"l.calpetard@otisud.com","CRM":"9360a373","Commentaire":"\\"Tr\00E8s bel \00E9v\00E9nement, bonne communication et organisation. Pourriez vous envisager d''organiser l''\00E9v\00E9nement sur 2 jours?\\"","Date":"21/5/2024","Moderer":"TRUE","Status":"Trait\00E9e","Humeur":"\+01F642","close_reqs":"TRUE","source_system":"berta_v2_csv_export"}', 'pending', 'false'),
('old-data-berta2-all-20260501-01', 'ff3dbe2b', '322a7d81', 'l.calpetard@otisud.com', U&'"Belle \00E9quipe, belle organisation. Ravi de participer \00E0 cet \00E9v\00E8nement et dans la bonne humeur. Am\00E9liorations \00E9ventuelles : fournir le plan aux prestataires pour avoir une id\00E9e de leur position et prendre en compte leur \00E9ventuelle remarque et d\00E9placement si n\00E9cessaire, et organiser un horaire d\00E9pose minute avec un battement de 5 \00E0 10 minutes uniquement pour charger/d\00E9charger le v\00E9hicule. Bonne continuation :)"', '2024-05-21 00:00:00', U&'\+01F642', U&'Trait\00E9e', 'true', 'true', 'Commentaires', U&'{"ID":"ff3dbe2b","User":"l.calpetard@otisud.com","CRM":"322a7d81","Commentaire":"\\"Belle \00E9quipe, belle organisation. Ravi de participer \00E0 cet \00E9v\00E8nement et dans la bonne humeur. Am\00E9liorations \00E9ventuelles : fournir le plan aux prestataires pour avoir une id\00E9e de leur position et prendre en compte leur \00E9ventuelle remarque et d\00E9placement si n\00E9cessaire, et organiser un horaire d\00E9pose minute avec un battement de 5 \00E0 10 minutes uniquement pour charger/d\00E9charger le v\00E9hicule. Bonne continuation :)\\"","Date":"21/5/2024","Moderer":"TRUE","Status":"Trait\00E9e","Humeur":"\+01F642","close_reqs":"TRUE","source_system":"berta_v2_csv_export"}', 'pending', 'false'),
('old-data-berta2-all-20260501-01', '6028de9e', '69f9cd66', 'l.calpetard@otisud.com', U&'"Bien organis\00E9 dans l''ensemble, avec une \00E9quipe dynamique mais peut-\00EAtre plus de promotion (ma voisine, qui travaille \00E0 la mairie, n''\00E9tait pas au courant.. ! ) l''artisanat est pl\00E9biscit\00E9 et pourtant il ne fait plus recette  dans les expos alors qu''il se vend bien dans les magasins, alors que bien plus cher !?...et peut-\00EAtre la date aussi, trop de monde parti. Bref, \00E7a devient compliqu\00E9 . En tout cas vous n''avez pas d\00E9m\00E9rit\00E9."', '2024-05-21 00:00:00', 'ok', U&'Trait\00E9e', 'true', 'true', 'Commentaires', U&'{"ID":"6028de9e","User":"l.calpetard@otisud.com","CRM":"69f9cd66","Commentaire":"\\"Bien organis\00E9 dans l''ensemble, avec une \00E9quipe dynamique mais peut-\00EAtre plus de promotion (ma voisine, qui travaille \00E0 la mairie, n''\00E9tait pas au courant.. ! ) l''artisanat est pl\00E9biscit\00E9 et pourtant il ne fait plus recette  dans les expos alors qu''il se vend bien dans les magasins, alors que bien plus cher !?...et peut-\00EAtre la date aussi, trop de monde parti. Bref, \00E7a devient compliqu\00E9 . En tout cas vous n''avez pas d\00E9m\00E9rit\00E9.\\"","Date":"21/5/2024","Moderer":"TRUE","Status":"Trait\00E9e","Humeur":"ok","close_reqs":"TRUE","source_system":"berta_v2_csv_export"}', 'pending', 'false'),
('old-data-berta2-all-20260501-01', '3bfb94c4', 'da5a367c', 'l.calpetard@otisud.com', U&'"Sur 2 jours se serait super. Vraiment enchant\00E9 par l organisation, le personnel, le lieu, etc... Une r\00E9ussite !!! Bravo \00E0 tous !"', '2024-05-21 00:00:00', U&'\+01F642', U&'Trait\00E9e', 'true', 'true', 'Commentaires', U&'{"ID":"3bfb94c4","User":"l.calpetard@otisud.com","CRM":"da5a367c","Commentaire":"\\"Sur 2 jours se serait super. Vraiment enchant\00E9 par l organisation, le personnel, le lieu, etc... Une r\00E9ussite !!! Bravo \00E0 tous !\\"","Date":"21/5/2024","Moderer":"TRUE","Status":"Trait\00E9e","Humeur":"\+01F642","close_reqs":"TRUE","source_system":"berta_v2_csv_export"}', 'pending', 'false');
